import React, { useState, useEffect } from "react";
import { graphql, useStaticQuery, navigate } from "gatsby";
import Layout from "../components/layout";
import Seo from "../components/seo";
import headerImage from '../images/shaun-hero-v3.jpg';
import PostList from "../components/post-list";
import CategoryButtons from "../components/category-buttons";
import FeaturedPost from "../components/featured-post";
import Pagination from "../components/pagination-new";

const IndexPage = ({ location }) => {
  const data = useStaticQuery(graphql`
    query {
      categories: allMarkdownRemark {
        group(field: {frontmatter: {category: SELECT}}) {
          fieldValue
        }
      }
      allPosts: allMarkdownRemark(sort: {frontmatter: {date: DESC}}) {
        edges {
          node {
            frontmatter {
              title
              date(formatString: "YYYY/MM/DD")
              slug
              category
              excerpt
              image {
                childImageSharp {
                  gatsbyImageData(layout: FULL_WIDTH)
                }
              }
            }
            rawMarkdownBody
          }
        }
      }
      site {
        siteMetadata {
          siteUrl
        }
      }
    }
  `);

  const getInitialCategory = () => {
    if (typeof window !== 'undefined') {
      return new URL(window.location).searchParams.get('category') || localStorage.getItem('selectedCategory') || 'All';
    }
    return 'All';
  };

  const getInitialLoadMoreCount = () => {
    if (typeof window !== 'undefined') {
      return parseInt(new URL(window.location).searchParams.get('count')) || parseInt(localStorage.getItem('loadMoreCount')) || 8;
    }
    return 8;
  };

  const [selectedCategory, setSelectedCategory] = useState(getInitialCategory());
  const [loadMoreCount, setLoadMoreCount] = useState(getInitialLoadMoreCount());

  useEffect(() => {
    localStorage.setItem('selectedCategory', selectedCategory);
    localStorage.setItem('loadMoreCount', loadMoreCount);

    if (typeof window !== 'undefined') {
      const url = new URL(window.location);
      if (selectedCategory === "All") {
        url.searchParams.delete('category');
        url.searchParams.delete('count');
      } else {
        url.searchParams.set('category', selectedCategory);
        url.searchParams.set('count', loadMoreCount);
      }
      window.history.replaceState({}, '', url);
    }
  }, [selectedCategory, loadMoreCount]);

  const handleCategoryChange = (category) => {
    setSelectedCategory(category);
    setLoadMoreCount(8);
  };

  const handleLoadMore = () => {
    setLoadMoreCount(loadMoreCount + 8);
  };

  const handleLinkClick = () => {
    if (typeof window !== "undefined") {
      localStorage.setItem('currentPage', "1");
    }
  };

  const today = new Date();
  const todayFormatted = today.toLocaleDateString('en-CA', {
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).replace(/-/g, '/');

  const allPosts = data.allPosts.edges.filter(({ node }) => {
    const postDate = new Date(node.frontmatter.date);
    const postDateFormatted = postDate.toLocaleDateString('en-CA', {
      year: 'numeric',
      month: '2-digit',
      day: '2-digit'
    }).replace(/-/g, '/');
    return postDateFormatted <= todayFormatted;
  });

  const firstPost = allPosts.length > 0 ? allPosts[0].node : null;

  const filteredPosts = selectedCategory === "All"
    ? allPosts.slice(1, loadMoreCount + 1)
    : allPosts.filter(({ node }) => node.frontmatter.category === selectedCategory).slice(0, loadMoreCount);

  const { siteUrl } = data.site.siteMetadata;

  const itemListElement = filteredPosts.map(({ node }, index) => {
    const { date, slug } = node.frontmatter;
    const dateObj = new Date(date);
    const year = dateObj.getFullYear();
    const month = ('0' + (dateObj.getMonth() + 1)).slice(-2);
    const day = ('0' + dateObj.getDate()).slice(-2);

    return {
      "@type": "ListItem",
      "position": index + 1,
      "url": `${siteUrl}/${year}/${month}/${day}/${slug}`
    };
  });

  const structuredData = {
    "@context": "http://schema.org",
    "@type": "ItemList",
    "itemListElement": itemListElement
  };

  const categories = ["All", ...data.categories.group.map(group => group.fieldValue)];

  return (
    <>
      <Seo
        title="Chronicles of a Millennial Techie"
        description="Discover a millennial techie's personal insights on growth, learning, LGBTQ+ and minority issues, mental health, and navigating life's modern complexities."
        meta={[{ name: 'keywords', content: 'Shaun Pezeshki, Technical Strategist, Marketing, Technology, Millennial Techie' }]}
        image={headerImage}
      />
      <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(structuredData) }}></script>
      <Layout>
        <section className="homepage plant">
          <div className="content">
            <div className="container">
              <div className="prose prose-xl">
                <h1>Chronicles of a Millennial Techie</h1>
                <p>I started this blog as a space to share my experiences as a millennial navigating life. What began as a personal outlet has grown into a community for growth, learning, and connection. This journey is as much yours as it is mine, offering you a mirror to see your own reflections differently. Together, let's uncover insights that challenge and reshape our perspectives.</p>
              </div>
            </div>
          </div>
          <FeaturedPost post={firstPost} handleLinkClick={handleLinkClick} />
          <CategoryButtons 
            categories={categories} 
            selectedCategory={selectedCategory} 
            handleCategoryChange={handleCategoryChange} 
          />
          <div className="container home">
            <PostList posts={filteredPosts} handleLinkClick={handleLinkClick} />
            <Pagination 
              hasMore={filteredPosts.length < (selectedCategory === "All" ? allPosts.length - 1 : allPosts.filter(({ node }) => node.frontmatter.category === selectedCategory).length)} 
              handleLoadMore={handleLoadMore} 
            />
          </div>
        </section>
      </Layout>
    </>
  );
};

export default IndexPage;
